// ===== 工具函數 =====

// 日期格式化函數（處理字串型日期）
function formatStringDate(dateStr) {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return dateStr;
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// 電話格式化函數
function formatPhone(phone) {
  if (!phone) return '';

  let phoneStr = String(phone).trim();
  let cleanPhone = phoneStr.replace(/[\s\-()]/g, '');

  if (cleanPhone.startsWith('+886')) {
    cleanPhone = '0' + cleanPhone.substring(4);
  } else if (/^9\d{8}$/.test(cleanPhone)) {
    cleanPhone = '0' + cleanPhone;
  }

  return cleanPhone;
}

// 性別轉換
function convertGender(gender) {
  if (!gender) return '';
  const genderStr = String(gender).toLowerCase().trim();
  const genderMap = {
    'mister': '男',
    'mr': '男',
    'male': '男',
    'miss': '女',
    'ms': '女',
    'mrs': '女',
    'female': '女'
  };
  return genderMap[genderStr] || gender;
}

// 簽約人清理（移除稱謂與空格）
function cleanSignerName(name) {
  if (!name) return '';
  let cleaned = String(name).trim();
  cleaned = cleaned.replace(/先生|小姐/g, ''); // 移除稱謂
  cleaned = cleaned.replace(/\s+/g, '');        // 移除所有空格
  return cleaned;
}

// 💡 [新增] 智慧案名解析函數
function parseProjectInfo(rawName, rawRoom) {
  let name = String(rawName || "").trim();
  let room = String(rawRoom || "").trim();

  let searchKey = name;
  let roomSuffix = "";

  // 1. 剃除可能的前綴系統編號 (例 "178博愛三路...", "273.至善路A")
  let prefixMatch = searchKey.match(/^(\d+)[\.\s]*/);
  if (prefixMatch) {
      searchKey = searchKey.substring(prefixMatch[0].length).trim();
  }

  // 2. 處理結尾的英文房號 (例 " B", "E", "Room C", "-D")
  let letterMatch = searchKey.match(/(?:\s*Room\s*|\s*-\s*|\s+)?([A-Za-z])$/i);
  if (letterMatch) {
      roomSuffix = letterMatch[1].toUpperCase();
      searchKey = searchKey.substring(0, searchKey.length - letterMatch[0].length).trim();
  } 
  // 3. 處理結尾的純數字房號 (例 "四川三街303")
  else {
      let numberMatch = searchKey.match(/(\d{3,4})$/);
      if (numberMatch && searchKey.length > numberMatch[0].length) {
          roomSuffix = numberMatch[1];
          searchKey = searchKey.substring(0, searchKey.length - numberMatch[0].length).trim();
      }
  }

  // 4. 雙重保險：如果案名拆不出房號，找原來的 `第__室`
  if (!roomSuffix && room) {
      let roomParts = room.split('-'); 
      roomSuffix = roomParts[roomParts.length - 1].trim(); 
  }

  return {
      searchKey: searchKey,
      roomSuffix: roomSuffix
  };
}

// ===== 主流程 =====
const outputItems = [];

for (let item of $input.all()) {
  const newItem = { ...item };

  // ===== 日期處理（只處理字串日期欄位） =====
  const stringDateFields = ['起租日', '到期日', '簽約日'];
  for (let field of stringDateFields) {
    if (newItem.json[field]) {
      newItem.json[field] = formatStringDate(newItem.json[field]);
    }
  }

  // ===== 電話欄位格式化 =====
  const phoneFields = ['電話', '緊急電話'];
  for (let field of phoneFields) {
    if (newItem.json[field]) {
      newItem.json[field] = formatPhone(newItem.json[field]);
    }
  }

  // ===== 性別轉換 =====
  if (newItem.json['性別']) {
    newItem.json['性別'] = convertGender(newItem.json['性別']);
  }

  // ===== 簽約人清理 =====
  if (newItem.json['簽約人']) {
    newItem.json['簽約人'] = cleanSignerName(newItem.json['簽約人']);
  }

  // 💡 [新增] 案名解析與變數賦值
  const projectInfo = parseProjectInfo(newItem.json['案名'], newItem.json['第__室']);
  newItem.json['解析_搜尋關鍵字'] = projectInfo.searchKey;
  newItem.json['解析_房間尾碼'] = projectInfo.roomSuffix;

  outputItems.push(newItem);
}

// ===== 返回輸出 =====
return outputItems;

// ===== 1. 工具函數模組 =====

function countChineseChars(text) {
  if (!text) return 0;
  return (text.match(/[\u4e00-\u9fa5]/g) || []).length;
}

function getFinalSiteInfo(rawRoom, searchedSiteId, fullRoom) {
  const room = String(rawRoom || "").trim();
  const searchedId = String(searchedSiteId || "").trim();
  if (room.includes('-')) {
    const site = room.split('-')[0].trim();
    return { site: site, room: room, abnormal: false, reason: '' };
  }
  if (searchedId !== "") {
    return { site: searchedId, room: String(fullRoom || room), abnormal: false, reason: '' };
  }
  return { 
    site: '', room: room, abnormal: true, 
    reason: room === '' ? '第__室欄位不可為空' : '無法解析案場編號' 
  };
}

function formatInternationalPhone(phone) {
  if (!phone) return "";
  let p = String(phone).trim();
  // 移除所有非數字字元，但保留可能存在的 + 號
  let digits = p.replace(/[^\d+]/g, '');
  return digits;
}

/**
 * 💡 優化後的姓名處理：加入法人判定
 */
function processName(name, isDualTenant, isTwId, isCorporate) {
  if (!name) return { n1: "", n2: "", abnormal: false, splitAction: false };
  let nameStr = String(name).trim();
  const totalChinese = countChineseChars(nameStr);
  const hasLetters = /[a-zA-Z]/.test(nameStr);

  // 1. 法人判定：如果是法人，直接去除空格合併
  if (isCorporate) {
    return { n1: nameStr.replace(/\s+/g, ''), n2: "", abnormal: false, splitAction: false };
  }

  // 2. 標準雙人判定
  if (isDualTenant) {
    const separators = ['/', '\\', '&', '、', '，', ','];
    for (let sep of separators) {
      if (nameStr.includes(sep)) {
        let parts = nameStr.split(sep).map(n => n.trim()).filter(n => n);
        return { n1: parts[0] || "", n2: parts[1] || "", abnormal: parts.length > 2, splitAction: true };
      }
    }
    let parts = nameStr.split(/\s+/).filter(p => p);
    if (parts.length >= 2) return { n1: parts[0], n2: parts[1], abnormal: false, splitAction: true };
  }

  // 3. 隱性雙人偵測 (本國籍、單證件、純中文 > 4字)
  if (!isDualTenant && isTwId && !hasLetters && totalChinese > 4) {
    let parts = nameStr.split(/\s+/).filter(p => p);
    if (parts.length >= 2) {
      return { n1: parts[0], n2: parts[1], abnormal: true, splitAction: true };
    }
    // 如果大於 8 個字且無空格，雖然是本國籍 ID 但極可能是法人誤植為個人 ID，標記異常
    if (totalChinese > 8) return { n1: nameStr, n2: "", abnormal: true, splitAction: false };
  }

  // 4. 標準台灣姓名 (2-4 字)
  if (!hasLetters && totalChinese >= 2 && totalChinese <= 4) {
    return { n1: nameStr.replace(/\s+/g, ''), n2: "", abnormal: false, splitAction: false };
  }

  return { n1: nameStr, n2: "", abnormal: false, splitAction: false };
}

// ===== 2. 主流程 =====
const outputItems = [];
const items = $input.all();

const relationStandard = {
  '父母': ['父母', '父親', '母親', '爸爸', '媽媽', '父', '母', 'Father', 'Mother', 'Parent'],
  '夫妻': ['夫妻', '配偶', '丈夫', '妻子', '老公', '老婆', '先生', '太太', '伴侶', '另一半', 'Spouse', 'Wife', 'Husband'],
  '兄弟姊妹': ['兄弟姊妹', '兄弟姐妹', '兄弟', '兄妹', '姊妹', '姊弟', '姐妹', '姐弟', '哥哥', '弟弟', 'Sister', 'Brother', 'Sibling'],
  '其他親戚': ['親戚', '叔叔', '阿姨', '舅舅', '姑姑', '兒子', '女兒', 'Relative', 'Son', 'Daughter']
};

for (let i = 0; i < items.length; i++) {
  const inputJson = items[i].json;
  const json = {}; 
  const remarks = [];

  const rawName = String(inputJson['姓名'] || inputJson['承租方'] || "");
  const rawId = String(inputJson['身分證字號'] || "").trim().toUpperCase();
  const rawPhone = String(inputJson['電話'] || "");
  const rawRel = String(inputJson['緊急聯絡人關係'] || "").trim();
  const rawRoom = String(inputJson['第__室'] || "");
  const searchedSiteId = inputJson['案場編號']; 
  const fullRoom = inputJson['完整房號'];

  // 1. 判定身分性質
  let isTwId = /^[A-Z][12]\d{8}$/.test(rawId);
  let isCorporate = /^\d{8}$/.test(rawId); // 💡 8位純數字判定為法人

  // 2. 案場處理
  const siteRes = getFinalSiteInfo(rawRoom, searchedSiteId, fullRoom);
  json['案場編號'] = siteRes.site;
  json['第__室'] = siteRes.room;
  if (siteRes.abnormal) remarks.push(siteRes.reason);

  // 3. 雙人基礎判定
  let isDualId = rawId.includes('/');
  let isDualPhone = rawPhone.includes('.');
  let isDualTenant = isDualId || rawName.includes('/') || rawName.includes('、') || isDualPhone;

  // 4. 姓名處理
  const nameRes = processName(rawName, isDualTenant, isTwId, isCorporate);
  json['姓名1'] = nameRes.n1;
  json['姓名2'] = nameRes.n2;
  json['姓名異常'] = nameRes.abnormal;

  // 5. 電話長度校驗 (台灣手機 10 位, 市話 9-10 位)
  let cleanPhone = rawPhone.replace(/\D/g, '');
  if (cleanPhone.length > 10) {
    remarks.push("電話長度異常");
  }

  // 6. 關係處理
  json['關係格式不符'] = true;
  json['緊急聯絡人關係'] = '待修正';
  for (const [stdKey, variants] of Object.entries(relationStandard)) {
    if (variants.some(v => rawRel.toLowerCase().includes(v.toLowerCase()))) {
      json['緊急聯絡人關係'] = stdKey;
      json['關係格式不符'] = (rawRel !== stdKey);
      break;
    }
  }
  if (json['緊急聯絡人關係'] === '待修正') {
    remarks.push("緊急聯絡人資料不符標準輸入格式");
  }

  // 7. 原始資料備份
  json['身分證字號1'] = rawId;
  json['身分證字號2'] = "";
  json['原始姓名資料'] = rawName;
  json['關係人原始值'] = rawRel;
  json['原始電話值'] = rawPhone;
  json['原始房號'] = rawRoom;

  // 8. 地址分配
  json['緊急聯絡人地址1'] = ""; json['緊急聯絡人地址2'] = "";
  json['房客戶籍地址'] = inputJson['戶籍地址'] || "";
  json['房客通訊地址'] = inputJson['通訊地址'] || "";

  json['電話1'] = formatInternationalPhone(rawPhone);
  json['電話2'] = "";

  // 9. 最終判定：只要有備註(含電話長度、關係不符)或案場異常，總體異常即為 true
  json['異常'] = json['姓名異常'] || siteRes.abnormal || remarks.length > 0;
  json['備註'] = remarks.join('，');

  outputItems.push({ json, pairedItem: i });
}

return outputItems;

const items = $input.all();
// 🌟 1. 抓回前一個節點 (假設叫 'If') 的原始資料
// 請確認括號內的名稱與您畫布上 IF 節點的名稱完全一致
const originalItems = $('If').all(); 

for (let i = 0; i < items.length; i++) {
    let siteId = "";
    let ragicData = items[i].json; 

    // 🌟 2. 智慧提取案場編號 (處理 Ragic 特有的 Key 結構)
    let keys = Object.keys(ragicData);
    if (keys.length > 0) {
        // 抓取第一個 Key (即 ragicId) 內部的案場編號
        let firstKey = keys[i % keys.length]; // 修正：如果 HTTP 回傳多筆則對應，若只有一筆則用 keys[0]
        // 安全做法通常是 keys[0]，因為我們是一筆一筆過來的
        siteId = ragicData[keys[0]] ? ragicData[keys[0]]["案場編號"] : "";
    }

    // 🌟 3. 抓取對應的原始資料 (含 解析_房間尾碼)
    let originalData = JSON.parse(JSON.stringify(originalItems[i].json));
    let suffix = originalData["解析_房間尾碼"] || "";

    // 🌟 4. 執行組合邏輯
    // 如果 siteId 為空 (搜尋失敗)，完整房號就輸出空值
    // 如果有 siteId，則組合成 ID-Suffix 格式
    let fullRoomId = "";
    if (siteId && siteId.trim() !== "") {
        fullRoomId = siteId + "-" + suffix;
    }

    // 🌟 5. 將結果寫入原始資料中
    originalData["案場編號"] = siteId;
    originalData["完整房號"] = fullRoomId;

    // 更新輸出
    items[i].json = originalData;
}

return items;
